class Solution {
public:
    bool canJump(vector<int>& nums) {
        int n = nums.size();

        int i = 0;
        while(i < n){
            int index = nums[i] + i;
            int highest = index;
            int high_index = i;
            for(int x = i; x < n && x <= index; x++){
                int temp = nums[x] + x;

                if (temp >= highest && nums[x] != 0){
                    highest = temp;
                    high_index = x;
                }
            }

            if(nums[high_index] + i > n-1){
                return true;
            }
            if (highest == index)
                return false;
            else{
                i = high_index;
            }
        }

        return true;

    }
};

